+/// Rearranges elements from channels into spatial dimensions.
+///
+/// Equivalent to `torch.nn.PixelShuffle(upscale_factor)`.
+/// Input: `(N, C * r^2, H, W)` → Output: `(N, C, H*r, W*r)`.
+pub struct PixelShuffle {
+    upscale_factor: usize,
+}
+
+impl PixelShuffle {
